public with sharing class DailyGospelService {
    @AuraEnabled(cacheable=true)
    public static String getDailyGospel() {
        Http http = new Http();
        HttpRequest req = new HttpRequest();
        String path = '/bible/readings/' + Date.today().format('MMddyy') + '.cfm';

        // USCCB dated page pattern: /bible/readings/MMDDYY.cfm
        // Direct endpoint used instead of a Named Credential. This requires a Remote Site Setting
        // for https://bible.usccb.org in the target org.
        req.setEndpoint('https://bible.usccb.org' + path);
        req.setMethod('GET');

        HttpResponse res = http.send(req);
        if (res.getStatusCode() == 200) {
            return res.getBody();
        } else {
            throw new AuraHandledException('Failed to retrieve daily gospel.');
        }
    }
}
